import{_ as t,o as a,c as r,a2 as n}from"./chunks/framework.ufzXw1qY.js";const p=JSON.parse('{"title":"Sovereign Security Mandate","description":"Zero-Trust and Auth-Broker standards for the OpenSIN ecosystem.","frontmatter":{"title":"Sovereign Security Mandate","description":"Zero-Trust and Auth-Broker standards for the OpenSIN ecosystem."},"headers":[],"relativePath":"governance/security-mandate.md","filePath":"governance/security-mandate.md"}'),o={name:"governance/security-mandate.md"};function i(s,e,d,c,l,u){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="sovereign-security-mandate" tabindex="-1">Sovereign Security Mandate <a class="header-anchor" href="#sovereign-security-mandate" aria-label="Permalink to &quot;Sovereign Security Mandate&quot;">​</a></h1><p>In the OpenSIN-AI ecosystem, security is not a feature; it is the foundation. We operate on a <strong>Zero-Trust</strong> model between agents.</p><h2 id="_1-the-auth-broker-pattern" tabindex="-1">1. The Auth-Broker Pattern <a class="header-anchor" href="#_1-the-auth-broker-pattern" aria-label="Permalink to &quot;1. The Auth-Broker Pattern&quot;">​</a></h2><p>Agents never hold long-lived credentials. All access to sensitive APIs (NIM, Groq, Stripe) must be brokered through the <a href="/guide/passwordmanager.html">Passwordmanager</a>.</p><h2 id="_2-evidence-first-auditing" tabindex="-1">2. Evidence-First Auditing <a class="header-anchor" href="#_2-evidence-first-auditing" aria-label="Permalink to &quot;2. Evidence-First Auditing&quot;">​</a></h2><p>Every destructive action (Write, Delete, Execute) must be logged with a pre-action screenshot and a post-action confirmation published to the Neural-Bus.</p><h2 id="_3-sandboxing-scoping" tabindex="-1">3. Sandboxing &amp; Scoping <a class="header-anchor" href="#_3-sandboxing-scoping" aria-label="Permalink to &quot;3. Sandboxing &amp; Scoping&quot;">​</a></h2><ul><li><strong>FileSystem:</strong> Agents are restricted to the project root unless explicitly authorized by the Operator.</li><li><strong>Network:</strong> Outbound calls to unverified domains are blocked by the default proxy.</li></ul><h2 id="_4-secret-redaction" tabindex="-1">4. Secret Redaction <a class="header-anchor" href="#_4-secret-redaction" aria-label="Permalink to &quot;4. Secret Redaction&quot;">​</a></h2><p>All audit logs and Telegram notifications must pass through the Redaction-Engine to prevent leak of API keys or PII.</p><hr><h2 id="⚖️-enforcement" tabindex="-1">⚖️ Enforcement <a class="header-anchor" href="#⚖️-enforcement" aria-label="Permalink to &quot;⚖️ Enforcement&quot;">​</a></h2><p>Non-compliant agents will be immediately disconnected from the Neural-Bus and moved to a quarantine branch for audit.</p><p>→ <a href="/architecture/security.html">View Full Security Specs</a></p>',14)])])}const m=t(o,[["render",i]]);export{p as __pageData,m as default};
